const ad = $json; // Obtém os dados do item atual

// Verifica se o campo pacing_type existe e tem valores
if (ad.pacing_type && ad.pacing_type.length > 0) {
    // Converte a lista pacing_type em uma string separada por vírgula
    ad.pacing_type_column = ad.pacing_type.join(", ");
}

// Remove o campo original "pacing_type"
delete ad.pacing_type;
ad.pacing_type = ad.pacing_type_column;
delete ad.pacing_type_column;

return { json: ad }; // Retorna o objeto modificado

